var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"안녕하세요, 저희 아쿠아리움에 오신 걸 환영합니다.","JPN":"こんにちは、アクアリウムへようこそ。","ENG":"Hello. Welcome to the aquarium.","TWN":"大家好，歡迎大家來到水族館。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"잠시 후에는 아쿠아리움 속 물고기들과 직접 소통하는 스노클링 체험이 진행될 예정입니다.","JPN":"間もなく、アクアリウム内のお魚たちとじかに触れ合えるシュノーケリング体験が行われる予定です。","ENG":"We will soon begin the snorkeling event, where visitors can communicate with fish inside our aquarium.","TWN":"稍後將要進行的是，可以和水族館裡的魚近距離接觸的浮潛體驗。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"스노클링 체험을 원하시는 분들은 안내 데스크에서 접수해주시기 바랍니다.","JPN":"シュノーケリング体験をご希望の方は、インフォメーションカウンターからお申込みください。","ENG":"For any visitors who wish to participate in the snorkeling event, please register at the information desk.","TWN":"想要體驗的人可以到我們的櫃台報名。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와아, 굉장해!","JPN":"わあ、すごい！","ENG":"Wow, this is amazing!","TWN":"哇，好美喔！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"박스 군, 저기 블루탱 좀 봐, 반짝반짝 귀여워!","JPN":"ダンボール君、あのナンヨウハギを見て。キラキラしててかわいい！","ENG":"Look at that Blue Tang, Boxie! It’s so cute!","TWN":"你看那隻多莉，長得好可愛喔！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L10_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"저기 가오리랑 커다란 상어도 있어! 와, 진짜 크구나!","JPN":"あそこにエイと大きいサメもいるよ！　わあ、本当に大きいんだね！","ENG":"There are also manta rays and giant sharks! Wow, they’re huge!","TWN":"那邊還有魟魚和鯊魚！超大的！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아하하…… 수족관이었구나…… 그럼 그렇지…….","JPN":"あはは……アクアリウムだったんだ……そりゃそうか……","ENG":"Ah ha ha... The aquarium, I see... I should have known better...","TWN":"哈哈哈……結果是水族館喔……也是啦……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 방금 뭐라고 했어, 박스 군?","JPN":"うん？　何か言った？　ダンボール君。","ENG":"Hmm? What did you just say?","TWN":"嗯？你剛說什麼？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 아뇨! 수, 수족관에는 어떻게 크고 작은 물고기들이 한 곳에 모여 있는지 궁금해서요!","JPN":"い、いいえ！　あ、アクアリウムではどうやって大小の魚を一か所に集めているのか気になって！","ENG":"N-nothing! I was just amazed by the diverse marine life they have here!","TWN":"沒…沒什麼！我只是很好奇，為什麼各種體型的魚可以生活在同一個空間裡呢！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"보통은 서로 잡아먹지 않을까…… 그런 궁금증이…… 아하하.","JPN":"普通は食べられたりするんじゃないかなーって……そんな疑問が……あはは。","ENG":"I thought they would kill and eat each other... Just curious, you know... Ah ha ha.","TWN":"牠們彼此不會自相殘殺嗎……有點好奇……哈哈哈。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아아, 공식을 말하는구나?","JPN":"ああ、共食いのことね？","ENG":"Ah, you mean cannibalism?","TWN":"喔喔，你是說同類相食嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"공식이요?","JPN":"共食い？","ENG":"Cannibalism?","TWN":"同類相食？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응. 박스 말대로 수족관처럼 물고기들을 같은 곳에 모아두면 같은 종이라도 서로 포식자와 피식자 관계가 될 수 있거든. 그게 공식이야.","JPN":"うん。ダンボール君の言うとおり、アクアリウムみたいに魚を同じところに集めておくと、同じ種でもお互い捕食者と被食者の関係になることがあるの。それが共食い。","ENG":"Yes. Like you said... When put inside a closed environment, fish can behave aggressively and kill each other, even if they’re of the same species. That’s cannibalism.","TWN":"嗯，就像你說的，將魚群放在同一個空間裡，像水族館這樣，相同種類的魚會形成捕食者和被捕食者的關係，這就是同類相食。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그래서 공식을 방지하기 위해, 수족관은 물고기들에게 충분한 먹이를 제공하곤 해.","JPN":"だから共食いを防ぐために、アクアリウムは魚に十分なエサを提供したりするの。","ENG":"So to prevent that from happening, aquariums make sure to give them enough food.","TWN":"而水族館都會供應魚群足夠的食物，以防止同類相食的情況發生。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"다시 말해, 먹을 게 풍족하니까 수족관 내 평화가 유지된다는 말이려나? 하하.","JPN":"つまり、食べ物が豊富だからアクアリウム内の平和が保たれてるってことかな。はは。","ENG":"In other words, peace is only made inside this aquarium because there’s no need to hunt.","TWN":"也就是說，當食物供應充足時，就可以維持水族館內的和平嗎？哈哈。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOG_NPC_GAMECIRCLE_NULL","text":{"KOREA":"멍!","JPN":"ワン！","ENG":"Woof!","TWN":"汪！汪"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE"},{"id":"L21_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아아, 그렇구나. 누나는 생물을 정말 좋아하시나 봐요.","JPN":"ああ、そうか。タエさんは生き物が大好きなんですね。","ENG":"Oh, I see. You must be really into biology.","TWN":"喔～原來是這樣，妲茵姊姊很喜歡動物吧？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응. 나 사실 퀸기도라나 고메가 같은 거대 괴수를 무척 좋아하거든.","JPN":"うん。実は私、クイーンギドラとかゴメガみたいな巨大怪獣が大好きなの。","ENG":"Yes. I’m actually into giant tyrants like Queen Ghidora or Gomega.","TWN":"嗯，像是王后基多拉，或哥梅加這類的巨型怪獸我都很愛。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"개인적으로 좋은 괴수 디자인은 현실 생물의 생물학적 특징에 대한 고증이 필요하다고 생각해.","JPN":"個人的に、いい怪獣のデザインは現実の生き物の生物学的な特徴についての考証が必要だと思うのよね。","ENG":"Personally, I think historical research on real-life animals is the key to creating a good monster design.","TWN":"我個人認為，要設計出好的怪獸，事前必須先針對生物特徵進行考證。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그래서 이것저것 관찰하고 공부하다 보니…… 엇! 너무 내 이야기만 했나?","JPN":"それでいろいろ観察して勉強してたら……あっ！　私ったら自分の話ばっかりしちゃったね？","ENG":"That’s why I study and observe a lot of things... Ah! Sorry. I talk too much, don’t I?","TWN":"所以我都會觀察得很仔細，然後……哎呀！好像都是我在說話？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"앗, 아니에요. 재밌었는데요? 뭐, 사람마다 취향은 다양하니까요.","JPN":"あっ、いいえ。面白かったですよ？　まあ、人それぞれ好みは違うものですから。","ENG":"Oh, not at all. It was interesting! People have different tastes and preferences, you know.","TWN":"喔，沒關係，還蠻有趣的，每個人的興趣都不一樣嘛。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"나, 사실…… 박스 군에게 사과해야할 게 있어.","JPN":"実は私……ダンボール君に謝らないといけないことがあるの。","ENG":"To be honest... I owe you an apology, Boxie.","TWN":"其實……我要跟你道歉。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"응? 사과라고요?","JPN":"え？　謝るって？","ENG":"Huh? An apology?","TWN":"什麼？跟我道歉？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그게…… 리네가 카운터즈 사가를 격투 게임으로 기획하지 않은 이유…… 나 때문이거든.","JPN":"あのね……マリちゃんがカウンターズ・サーガを格ゲーに企画しなかった理由……私のせいなんだ。","ENG":"Well... The reason why Rinae didn’t make Counters Saga a fighting game was me.","TWN":"就是……璃奈之所以沒有把制裁者傳奇製作成格鬥遊戲……是因為我的關係。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네?","JPN":"え？","ENG":"Huh?","TWN":"為什麼？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"사실, 카운터즈 사가는 스트리트 카운터처럼 격투게임으로 기획되었어.","JPN":"実は、カウンターズ・サーガはストリート・カウンターみたいに格ゲーとして企画されてたの。","ENG":"Counters Saga was originally designed as a fighting game, like Street Counter.","TWN":"原本的規劃，是要把制裁者傳奇製作成像街頭制裁者那樣的格鬥遊戲的。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하지만 리네는 우리 모두가 만족할 수 있는 게임을 만들기를 바랬어.","JPN":"でもマリちゃんは、私たちみんなが満足できるようなゲームを作りたいって。","ENG":"But Rinae wanted to make a game where everyone feels included.","TWN":"但是璃奈希望可以做出一個大家都能滿意的遊戲。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그래서 내 취향이 게임에 반영될 수 있게 게임 장르를 바꾼 거야.","JPN":"それで、私の好みがゲームに反映されるように、ゲームのジャンルを変えたの。","ENG":"That’s why she changed the genre of the game, to make room for my personal taste.","TWN":"所以才會改變類型，在遊戲裡加入我喜歡的元素。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"일대일 격투 게임에서 몬스터가 잔뜩 등장하는 장르로.","JPN":"一対一の格ゲーから、モンスターがいっぱい登場するジャンルに。","ENG":"From a one-on-one fighting game to a game packed with various monsters.","TWN":"就是從一對一的格鬥遊戲，改成有很多怪物出現的類型。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그런 사정이…….","JPN":"そ、そんな事情が……","ENG":"I-I didn’t know...","TWN":"原…原來有這件事……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하지만 박스 군에게 스트리트 카운터는 소중한 게임이잖아?","JPN":"でも、ダンボール君にとってストリート・カウンターは大事なゲームでしょ？","ENG":"But I know Street Counter holds a special place in your heart, Boxie.","TWN":"你這麼喜歡街頭制裁者，"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어쨌든 결과적으로는 그게…… 박스 군의 팬심을 짓밟는 일이 된 게 아닐까 싶어서…….","JPN":"とにかく結果的にはそれが……ダンボール君の心を踏みにじることになったんじゃないかなって……","ENG":"Whatever the case may be... I felt that we might've trampled on your love and passion...","TWN":"就結果而言……可能還是有傷害到你對遊戲的熱愛……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그래서 꼭 미안하다는 말을 전하고 싶었어. 미안해, 박스 군.","JPN":"それで絶対ごめんって伝えたかったの。ごめんね、ダンボール君。","ENG":"Which is why I wanted to apologize. I’m sorry, Boxie.","TWN":"所以我一定要跟你道歉，對不起。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"마, 꼬맹이! 정신차리라! 와 그라는데?","JPN":"ちょっと、じゃりんこ！　しっかりせえ！　どうしたん？","ENG":"Hey, kiddo! Snap outtavit! What’s goin’ on?","TWN":"小…小朋友！你怎麼啦？沒事吧？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"왜 그러냐고요? 누나들이 제 덕심을 산산조각냈잖아요!","JPN":"どうしたもなにも、みなさんが僕のオタク心を壊したんじゃないですか！","ENG":"What’s going on? I’ll tell you, you shattered my hopes and dreams!","TWN":"為什麼？你們為什麼要破碎我對這個遊戲的愛！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그건……. 저는…….","JPN":"そ、それは……僕は……","ENG":"Th-that’s.... I...","TWN":"喔…那個喔……我……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"DOG_NPC_GAMECIRCLE_NULL","text":{"KOREA":"크르르르르! 멍, 멍!","JPN":"ガルルルルル！　ワン、ワン！","ENG":"Grrrrrr...! Woof! Woof!","TWN":"汪汪汪汪汪！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_07"},{"id":"L48_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"음?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"VISITOR_EXTRA_ADMIN_A","text":{"KOREA":"저기 봐! 갑자기 상어가 유리 벽에 몸을 들이받고 있어!","JPN":"あれ見ろ！　いきなりサメが水槽に体当たりしだしたぞ！","ENG":"Look over there! That shark is slamming its body against the glass!","TWN":"你看！鯊魚突然一直用身體撞玻璃欸！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"VISITOR_EXTRA_ADMIN_B","text":{"KOREA":"직원 불러야 하는 거 아니야!? 지금 이쪽에서 사람들 스노클링 체험하고 있잖아!","JPN":"職員を呼んだ方がいいんじゃないか！？　今こっちでシュノーケリング体験してるんだぞ！","ENG":"Shouldn't we call someone? There are people snorkeling over here!","TWN":"是不是要找員工過來處理一下！？裡面現在不是有人正在體驗浮潛嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"VISITOR_EXTRA_ADMIN_A","text":{"KOREA":"무, 무슨 방법이 없나!? 저러다 물 속에 있는 사람들이 상어한테 공격당하겠어!","JPN":"な、何か方法はないのか！？　このままじゃ、水中にいる人たちがサメに攻撃される！","ENG":"W-what do we do?! They might get attacked by the shark!","TWN":"怎…怎麼辦！？這樣裡面的人會被鯊魚攻擊欸！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"잠깐, 이거 어쩌면 유리까지 깨질지도 몰라요! 다인 누나! 빨리 여길 피해야 해요!","JPN":"ちょっと、これってもしかしたら水槽が割れるかもしれませんよ！　タエさん！　早くここから逃げないと！","ENG":"Wait, if it keeps doing that, the glass might break! Dain! Let’s get out of here!","TWN":"等等，玻璃等一下很可能會被撞破！妲茵姊姊！我們快離開這裡！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L8_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나! 거긴 위험하다고요! 유리 벽에서 떨어지세요.","JPN":"タエさん！　そっちは危険です！　水槽から離れてください。","ENG":"Dain! It’s dangerous! Stay away from the glass.","TWN":"姊姊！這裡很危險！玻璃會破掉的！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"괜찮아…… 괜찮아…….","JPN":"大丈夫……大丈夫だよ……","ENG":"It's okay... It's okay...","TWN":"沒事的……沒事……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아무도 널 다치게 하지 않아…… 응응, 무서워할 거 없어…….","JPN":"誰もあなたを傷つけない……よしよし、怖くないよ……","ENG":"No one’s going to hurt you... Yes, there’s nothing to be scared of...","TWN":"沒有人會傷害你……乖，不用怕喔……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나……?","JPN":"タエさん……？","ENG":"Dain...?","TWN":"姊姊……？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"VISITOR_EXTRA_ADMIN_A","text":{"KOREA":"어, 어라? 갑자기 상어가 얌전해졌잖아?","JPN":"あ、あれ？　いきなりサメが大人しくなったぞ？","ENG":"H-huh? The shark suddenly turned docile...","TWN":"喂？鯊魚突然安靜下來咧？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L15_1","type":"dialog","speaker":"VISITOR_EXTRA_ADMIN_B","text":{"KOREA":"잠깐 흥분한 것뿐이었나? 그냥 별일 아니었나 보네?","JPN":"ちょっと興奮しただけだったのか？　大した事なかったみたいだな。","ENG":"Was it just temporarily annoyed? I guess it wasn’t a big problem after all.","TWN":"只是突然有點激動嗎？應該沒什麼事吧？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"금일, 스노클링 체험 행사는 내부 사정으로 인해, 취소되었습니다.","JPN":"本日のシュノーケリング体験イベントは事情により、キャンセルとなりました。","ENG":"Please be informed that the snorkeling event has been canceled due to internal issues.","TWN":"由於內部作業問題，今天浮潛體驗活動取消，"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"관람객 여러분께는 이점 참고하여……","JPN":"観覧客の皆様はご参考になり……","ENG":"Guest and visitors, thank you for your understanding...","TWN":"請各位遊客注意……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이, 이상하다? 방금 누나가 뭔가 속삭이니까 상어가 움직임을 멈추지 않았나?","JPN":"へ、変だな？　さっきタエさんが何か囁いたら、サメが動きを止めなかったか？","ENG":"Th-that was weird. As soon as Dain whispered something, the shark stopped moving...","TWN":"奇…奇怪？剛剛是因為姊姊講的悄悄話，鯊魚才安靜下來的嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L21_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"에이, 그냥 잘 못 본 거겠지? 이게 무슨 만화도 아니고…….","JPN":"まあ、ただの見間違いだよな？　漫画じゃないんだし……","ENG":"Nah, it can’t be. Reality is different from fiction...","TWN":"哎呀，應該是我眼花吧？又不是在演電影……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 박스 군! 저 쪽에도 신기한 물고기들이 많아! 빨리 가보자!","JPN":"ふふっ、ダンボール君！　あっちにも不思議な魚がいっぱいだよ！　早く行ってみよう！","ENG":"Heh heh, Boxie! There are more fish over there! Let’s go!","TWN":"嘿嘿，那邊也有很多奇妙的魚欸！我們快過去看看吧！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L26_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"엇, 누나!? 가, 갑자기 그렇게 손을 잡으시면……!?","JPN":"えっ、タエさん！？　い、いきなり、そんな、手を握って……！？","ENG":"Ah, Dain?! Y-you’re holding my hand...!","TWN":"唔，姊姊！？你這樣突然牽我的手……！？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DOG_NPC_GAMECIRCLE_NULL","text":{"KOREA":"멍! 멍!","JPN":"ワン！　ワン！","ENG":"Woof! Woof!","TWN":"汪汪！"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE"},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그런 일이 있었군요. 자칫 잘못하면 큰 사고가 발생할 뻔했네요.","JPN":"……そんなことがあったのか。危うく大事故が発生するところだったね。","ENG":"...I see. I’m glad nothing dangerous happened.","TWN":"……竟然有這種事，差點就發生重大意外呢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네, 그 옆 구역에서는 스노클링 체험을 하고 있어서 진짜 위험했어요.","JPN":"はい、その隣の区域ではシュノーケリング体験をやってて、本当に危なかったです。","ENG":"Yeah! It was a close call for the snorkelers in the next area!","TWN":"對啊，旁邊的區域正好在體驗浮潛，真的好危險。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"갑자기 상어가 얌전해지긴 했지만…….","JPN":"突然サメが大人しくなりはしましたけど……","ENG":"Thank goodness the shark turned gentle all of a sudden...","TWN":"雖然鯊魚後來有安靜下來……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그 아이…… 아무래도 사람들이 너무 많아서 깜짝 놀랐나 봐요.","JPN":"あの子……人が多すぎてビックリしたんだと思います。","ENG":"I think... it was surprised because there were too many people there.","TWN":"那孩子……只是因為人太多嚇到而已。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷! 상어 같은 게 뭐가 무섭다고 그러는데?","JPN":"へへっ！　サメなんて全然怖くなんかあらへんし！","ENG":"Heh! What’s so frightenin' about sharks, anyway?","TWN":"嘿嘿！鯊魚有啥好怕的？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어차피 이 미리네 님의 <color=#ffd34c>블리자드 슬래시</color> 한 방이면 그냥 냉동 참치 된다 아이가!","JPN":"どうせこのマリ様の<color=#ffd34c>ブリザード・スラッシュ</color>一発で冷凍マグロになるんやから！","ENG":"One hit from Mi Rinae’s <color=#ffd34c>Blizzard Slash</color>, and this shark will turn into frozen tuna!","TWN":"只要使出我的<color=#ffd34c>暴雪衝擊</color>，馬上讓牠變成鯊魚煙唄！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그 컨셉…… 이제 슬슬 질릴 때도 되지 않았어요?","JPN":"そのコンセプト……いいかげん飽きないんですか？","ENG":"Don’t you get tired of that concept?","TWN":"我說……你還演不膩喔？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐라노! 이거 컨셉 아니라고! 니 함 맞아 볼래?","JPN":"何言うてんねん！　これ、コンセプトじゃあらへんし！　あんた一発殴ってやろか？","ENG":"Concept?! This ain’t a concept! You really do need some whuppin’, don’t ya?","TWN":"你說啥呢！什麼演的！是不是想吃我一拳？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"질 것 같은데……? 물 속에서 싸우면?","JPN":"負けそうだけど……？　水の中で戦うと。","ENG":"You’ll lose... if you fight underwater.","TWN":"會輸吧……？在水裡的話？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"너 못 하잖아…… 수영.","JPN":"マリ、ダメじゃない……泳ぐの。","ENG":"Swim… you can’t.","TWN":"你又不會……游泳。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"보라 이 가스나가 뭐라노! 내 자신있다 안 하나!","JPN":"シホ、何言うてんねん！　ウチ自信はある言うたやん！","ENG":"What are you ramblin’ about, Bora?! I say bring it on!","TWN":"寶拉你在胡說啥呢！我有信心會贏！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 이건 어떨까요? 카운터즈 사가에서 미리네 양과 상어를 싸우게 하는 거죠.","JPN":"じゃあ、これはどうかな？　カウンターズ・サーガでマリ君とサメを戦わせるんだ。","ENG":"How about this, then? We make Rinae fight off a shark inside Counters Saga.","TWN":"那這樣吧？讓宓璃奈和鯊魚在制裁者傳奇裡決鬥！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와! 아틀란티스 같은 바닷속 던전이 있다면 재밌을 것 같아요!","JPN":"うわ！　アトランティスみたいな、海の中のダンジョンがあったら面白そうですね！","ENG":"Wow! An underwater dungeon that resembles Atlantis, perhaps?","TWN":"哇！像亞特蘭提斯那樣的海底地下城嗎？那應該會很酷吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼…… 리네가 어부가 되는 건가요? 후훗, 그건 그것대로…….","JPN":"じゃあ……マリちゃんが漁師になるんですか？　ふふっ、それはそれで……","ENG":"Then... is Rinae going to be a fisher? Fu fuu, that’ll be interesting...","TWN":"那……璃奈會變成漁夫嗎？呵呵，那樣的話……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"불가능해요…… 저희 게임에선……. 수중전.","JPN":"不可能です……私たちのゲームでは……水中戦。","ENG":"Marine battles… it’s impossible... in our game.","TWN":"海戰……我們的遊戲……不可能。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 이럴 땐 발상을 역전시켜보는 거죠. ","JPN":"はは、こういう時には逆の発想をしてみるんだ。 ","ENG":"Ha ha, that’s when we have to think outside of the box.","TWN":"哈哈，這種時候就要反向思考。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미리네 양이 물 속에 들어가는 게 아니라 상어를 물 밖으로 꺼내 보는 건 어떨까요?","JPN":"マリ君が水の中に入るのではなく、サメを水の外に出してみるのはどうだろう？","ENG":"Instead of making Rinae dive in, why not draw the shark out of the water?","TWN":"那不然，宓璃奈不用進到水裡，而是讓鯊魚離開海呢？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다인 양, 혹시 오늘 본 상어에 다리가 생긴다면 어떤 디자인일까요?","JPN":"タエ君、今日見たサメに足をつけたら、どんなデザインになるかな。","ENG":"Dain, what would a shark look like if it were to develop feet?","TWN":"妲茵，你今天看到的鯊魚長腳的話，會是什麼樣子？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"엇! 다리가 있는 물고기……!?","JPN":"えっ！　足のついた魚……！？","ENG":"Ah! A fish with femurs...?","TWN":"喔！有長腳的魚嗎……！？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하하! 저 그거 알아요! 애니메이션, <color=#ffd34c>데몬 슬레이어즈</color>에 나오는 어인족 말씀하시는 거 맞죠?","JPN":"あはは！　ウチ、それ知ってます！　アニメ、<color=#ffd34c>デーモン・スレイヤーズ</color>に出てくる魚人族のことですよね？","ENG":"Ah ha ha! I know! It’s that fishmen from <color=#ffd34c>D. Slayers</color>!","TWN":"哈哈哈！我知道！像動畫<color=#ffd34c>怪物魔導士</color>裡的半人魚那樣吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Mmm...","TWN":"嗯……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"만약 물고기에 다리가 있다면 양서류쪽이려나……?","JPN":"もし魚に足がついているなら、両生類が近いかな……？","ENG":"If a fish were to have legs... Would it be a fish or an amphibian...?","TWN":"魚長腳的話，那算是兩棲類嗎……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아니, 그건 너무 박력이 부족해. 좀 더 근육이 돋보이는 파충류 같은 디자인이라면……","JPN":"ううん、それじゃ迫力が足りなすぎ。もっと筋肉が目立つ爬虫類みたいなデザインなら……","ENG":"No, that’s too bland. Maybe a design with reptile features and more muscles...","TWN":"不行，這樣不夠有魄力！要是設計成肌肉發達的爬蟲類……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"다인 누나, 엄청 진지한 표정이야.","JPN":"タエさん、すごく真剣な顔してる。","ENG":"Dain... She’s really at it.","TWN":"妲茵姊姊的表情好認真。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그렇구나. 선생님이 말한 일상 속에서 힌트를 얻는다는 건 이런 의미였구나.","JPN":"そうか。先生が言ってた、日常の中でヒントを得るっていうのはこういう意味だったんだな。","ENG":"This is it. This must be a hint in our daily lives.","TWN":"原來老師是這個意思，這就是在生活中獲得靈感嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……아! 생각났다!","JPN":"……あ！　思いついた！","ENG":"...Ah! Eureka!","TWN":"……有了！我想到了！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"선생님! 저 연구실에 잠깐 들렸다가 갈래요!","JPN":"先生！　私、ちょっと部室に寄って帰ります！","ENG":"Teacher! I’m going to drop by the lab for a bit!","TWN":"老師！我要先去一趟研究社！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어쩐지…… 어쩐지 귀여운 아이를 그릴 수 있을 것 같거든요!","JPN":"なんだか……なんだかとてもかわいい子を描けそうな気がして！","ENG":"I think... I’ll be able to come up with something really cute!","TWN":"我……我好像可以畫出可愛的東西喔！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DOG_NPC_GAMECIRCLE_NULL","text":{"KOREA":"멍, 멍멍!","JPN":"ワン、ワンワン！","ENG":"Woof! Woof Woof!","TWN":"汪汪汪！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE"}]`);export{e as default};